RuleSet.GenFile:
#!/bin/bash # # @(#) $GenPackageDir$/$GenFileName$ $MssBashScriptLicense$ # # Initialize locals # oradatadir="" orapwd="" oraservice="" orahost="" oraport="" orauser="" logfilename="" parmerrors="" TK_DUALCASE_IN_CASE_STATEMENTS=true
# # Parse the command line options # while [ -n "$$1" ] do case "$$1" in
-D) shift oradatadir=$$1 shift ;;
-H) shift orahost=$$1 shift ;;
-L) shift logfilename=$$1 shift ;;
-P) shift orapwd=$$1 shift ;;
-p) shift oraport=$$1 shift ;;
-S) shift oraservice=$$1 shift ;;
-U) shift orauser=$$1 shift ;;
*) echo >&2 "ERROR: Option $$1 not recognized." parmerrors="Y" shift ;; esac done $CrDbSchemaValidateParameters$ $CrDbSchemaCreateTablespaces$ $CrDbSchemaCreateDbUser$ $CrDbSchemaCreateDbInstance$

RuleSet.GenRule:
#
#	Create the database user
#
echo "Creating user $lower DbSchemaName$ ..." | tee -a $${logfilename}

echo "" >>$${logfilename}
echo "#" >>$${logfilename}
echo "#	Create user $lower DbSchemaName$" >>$${logfilename}
echo "#" >>$${logfilename}

echo "create user $lower DbSchemaName$ identified by $${orapwd};" | $${sqlpluscmd} >>$${logfilename} 2>&1
echo "alter user $lower DbSchemaName$ quota unlimited on $lower DbSchemaName$_data1;" | $${sqlpluscmd} >>$${logfilename} 2>&1
echo "alter user $lower DbSchemaName$ quota unlimited on $lower DbSchemaName$_idx1;" | $${sqlpluscmd} >>$${logfilename} 2>&1

#
#	Create the database instance
#
echo "Creating database $lower DbSchemaName$ ..." | tee -a $${logfilename}

echo "" >>$${logfilename}
echo "#" >>$${logfilename}
echo "#	Create database $lower DbSchemaName$" >>$${logfilename}
echo "#" >>$${logfilename}

echo "create database $lower DbSchemaName$ tablespace $lower DbSchemaName$_data1;" | $${sqlpluscmd} >>$${logfilename} 2>&1

if [ "$${orahost}" == "" ]; then
	./$dbadminfilename_CreateSchema$ -U $${orauser} -P $${orapwd} -L $${logfilename}
else
	./$dbadminfilename_CreateSchema$ -H $${orahost} -U $${orauser} -P $${orapwd} -L $${logfilename}
fi
